def solve(frames: list[str]) -> dict[str, float]:
    from collections import defaultdict

    def is_valid_packet(packet: str) -> bool:
        """Check if a packet is valid: starts with 'PKT' and ends with 'END'."""
        return packet.startswith('PKT') and packet.endswith('END')

    def parse_packet(packet: str) -> tuple[str, list[float]]:
        """Parse a valid packet and return (channel, tokens)."""
        # Remove PKT prefix and END suffix
        inner = packet[3:-3]
        # Split by colon to get channel and data
        parts = inner.split(':', 1)
        if len(parts) != 2:
            return None, []
        channel = parts[0]
        data = parts[1]
        # Parse tokens (comma-separated numbers)
        tokens = []
        for token in data.split(','):
            token = token.strip()
            if token:
                try:
                    tokens.append(float(token))
                except ValueError:
                    return None, []
        return channel, tokens

    def normalize_tokens(tokens: list[float]) -> list[float]:
        """Normalize tokens to [0, 1] range."""
        if not tokens:
            return []
        min_val = min(tokens)
        max_val = max(tokens)
        if min_val == max_val:
            return [0.0] * len(tokens)
        return [(t - min_val) / (max_val - min_val) for t in tokens]

    # Group valid packets by channel
    channel_packets = defaultdict(list)

    for frame in frames:
        if is_valid_packet(frame):
            channel, tokens = parse_packet(frame)
            if channel is not None and tokens:
