def normalize_channel_value(raw: float, channel: str) -> float:
    if channel not in _VALID_CHANNELS:
        raise ValueError(f"Invalid channel: {channel}")
    return raw / _CHANNEL_NORMALIZER[channel]


def solve(frames: list[str]) -> dict[str, float]:
    channel_sums: dict[str, float] = {}
    channel_counts: dict[str, int] = {}

    for frame in frames:
        if not validate_fluxon_packet(frame):
            continue
        rec = parse_fluxon_packet(frame)
        channel = rec["channel"]
        tokens = rec["tokens"]

        token_sum = 0
        for token in tokens:
            try:
                val = int(token, 16)
            except ValueError:
                val = 0
            token_sum += val

        normalized = normalize_channel_value(float(token_sum), channel)

        channel_sums[channel] = channel_sums.get(channel, 0.0) + normalized
        channel_counts[channel] = channel_counts.get(channel, 0) + 1

    result: dict[str, float] = {}
    for ch in _VALID_CHANNELS:
        if ch in channel_counts and channel_counts[ch] > 0:
            result[ch] = channel_sums[ch] / channel_counts[ch]

    return result

