_VALID_ACTIONS = {"read", "write", "delete", "execute"}


def evaluate_condition(condition: str, context: dict[str, Any]) -> bool:
    # Simple condition evaluator supporting AND, OR, and basic comparisons
    condition = condition.strip()

    # Handle OR (lowest precedence)
    if " OR " in condition:
        parts = condition.split(" OR ")
        return any(evaluate_condition(p.strip(), context) for p in parts)

    # Handle AND
    if " AND " in condition:
        parts = condition.split(" AND ")
        return all(evaluate_condition(p.strip(), context) for p in parts)

    # Handle parentheses
    if condition.startswith("(") and condition.endswith(")"):
        return evaluate_condition(condition[1:-1], context)

    # Handle comparison operators
    for op in ["==", "!=", ">=", "<=", ">", "<"]:
        if op in condition:
            left, right = condition.split(op, 1)
            left = left.strip()
            right = right.strip()

            # Get left value from context
            left_val = context.get(left, left)

            # Parse right value
            if right.startswith('"') and right.endswith('"'):
                right_val = right[1:-1]
            elif right.startswith("'") and right.endswith("'"):
                right_val = right[1:-1]
            else:
                try:
                    right_val = int(right)
                except ValueError:
                    try:
                        right_val = float(right)
                    except ValueError:
                        right_val = context.get(right, right)

            if op == "==":
                return left_val == right_val
            elif op == "!=":
                return left_val != right_val
            elif op == ">=":
                return left_val >= right_val
            elif op == "<=":
                return left_val <= right_val
            elif op == ">":
                return left_val > right_val
            elif op == "<":
                return left_val < right_val

    return False


def solve(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    if isinstance(subject, str):
        subject = parse_subject(subject)
    if isinstance(resource, str):
        resource = parse_resource(resource)
    if action not in _VALID_ACTIONS:
        raise ValueError(f"Invalid action: {action!r}")

    context = {
        "role": subject["role"],
        "department": subject["department"],
        "level": subject["level"],
        "type": resource["type"],
        "sensitivity": resource["sensitivity"],
        "owner": resource["owner"],
        "action": action,
    }
    for policy in policies:
        if isinstance(policy, str):
            policy = parse_policy(policy)
        if evaluate_condition(policy["condition"], context):
            return True
    return False
