_VALID_ROLES = {"employee", "manager", "director", "admin", "auditor"}
_VALID_DEPARTMENTS = {"engineering", "finance", "hr", "legal", "operations", "sales", "marketing"}
_VALID_SENSITIVITIES = {"public", "internal", "confidential", "restricted"}


def _parse_kv_string(s: str) -> dict[str, Any]:
    """Parse a semicolon-separated key=value string into a dict."""
    rec = {}
    for part in s.split(";"):
        part = part.strip()
        if not part:
            continue
        key, value = part.split("=", 1)
        value = value.strip()
        # Try to convert to int if possible
        try:
            value = int(value)
        except ValueError:
            pass
        rec[key.strip()] = value
    return rec


def parse_subject(subject: str) -> dict[str, Any]:
    """Parse a subject string into a dictionary."""
    rec = _parse_kv_string(subject)
    if "role" not in rec or "department" not in rec or "level" not in rec:
        raise ValueError(f"Subject missing required fields: {subject!r}")
    if rec["role"] not in _VALID_ROLES:
        raise ValueError(f"Invalid role: {rec['role']!r}")
    if rec["department"] not in _VALID_DEPARTMENTS:
        raise ValueError(f"Invalid department: {rec['department']!r}")
    if not 1 <= rec["level"] <= 5:
        raise ValueError(f"Invalid level: {rec['level']!r}")
    return rec


def parse_resource(resource: str) -> dict[str, Any]:
    """Parse a resource string into a dictionary."""
    rec = _parse_kv_string(resource)
    if "type" not in rec or "sensitivity" not in rec or "owner" not in rec:
        raise ValueError(f"Resource missing required fields: {resource!r}")
    if rec["sensitivity"] not in _VALID_SENSITIVITIES:
        raise ValueError(f"Invalid sensitivity: {rec['sensitivity']!r}")
    if rec["owner"] not in _VALID_DEPARTMENTS:
        raise ValueError(f"Invalid owner department: {rec['owner']!r}")
    return rec


def parse_policy(policy: str) -> dict[str, Any]:
    """Parse a policy string into a dictionary."""
    rec = _parse_kv_string(policy)
    if "effect" not in rec or "condition" not in rec:
        raise ValueError(f"Policy missing required fields: {policy!r}")
    if rec["effect"] not in ("allow", "deny"):
        raise ValueError(f"Invalid effect: {rec['effect']!r}")
    return rec


def evaluate_condition(condition: str, context: dict[str, Any]) -> bool:
    """Evaluate a simple condition string against a context dictionary."""
    condition = condition.strip()

    # Handle AND
    if " AND " in condition:
        parts = condition.split(" AND ")
        return all(evaluate_condition(p.strip(), context) for p in parts)

    # Handle OR
    if " OR " in condition:
        parts = condition.split(" OR ")
        return any(evaluate_condition(p.strip(), context) for p in parts)

    # Handle comparison operators
    for op in ["==", "!=", ">=", "<=", ">", "<"]:
        if op in condition:
            left, right = condition.split(op, 1)
            left = left.strip()
            right = right.strip()

            # Get left value from context
            left_val = context.get(left, left)

            # Parse right value
            if right.startswith('"') and right.endswith('"'):
                right_val = right[1:-1]
            elif right.startswith("'") and right.endswith("'"):
                right_val = right[1:-1]
            else:
                try:
