def _parse_entity(entity_str: str, keys: list[str]) -> dict[str, Any]:
    """Parse a semicolon-separated key=value string into a dict."""
    result = {}
    for part in entity_str.split(";"):
        part = part.strip()
        if not part:
            continue
        key, value = part.split("=", 1)
        key = key.strip()
        value = value.strip()
        if key in ("level",):
            value = int(value)
        result[key] = value
    return result


