def parse_resource(resource: str) -> dict[str, Any]:
    return _parse_entity(resource, ["type", "sensitivity", "owner"])


def parse_policy(policy: str) -> dict[str, Any]:
    """Parse a policy string like 'allow role == "manager" and level >= 3'."""
    policy = policy.strip()
    if policy.startswith("allow "):
        effect = "allow"
        condition = policy[len("allow "):]
    elif policy.startswith("deny "):
        effect = "deny"
        condition = policy[len("deny "):]
    else:
        raise ValueError(f"Invalid policy: {policy!r}")
    return {"effect": effect, "condition": condition}


def _eval_condition_node(node: ast.AST, context: dict[str, Any]) -> Any:
    if isinstance(node, ast.BoolOp):
        if isinstance(node.op, ast.And):
            result = True
            for value in node.values:
                result = result and _eval_condition_node(value, context)
                if not result:
                    return False
            return result
        elif isinstance(node.op, ast.Or):
            result = False
            for value in node.values:
                result = result or _eval_condition_node(value, context)
                if result:
                    return True
            return result
    elif isinstance(node, ast.Compare):
        left = _eval_condition_node(node.left, context)
        for op, comparator in zip(node.ops, node.comparators):
            right = _eval_condition_node(comparator, context)
            if isinstance(op, ast.Eq):
                if not (left == right):
                    return False
            elif isinstance(op, ast.NotEq):
                if not (left != right):
                    return False
            elif isinstance(op, ast.Lt):
                if not (left < right):
                    return False
            elif isinstance(op, ast.LtE):
                if not (left <= right):
                    return False
            elif isinstance(op, ast.Gt):
                if not (left > right):
                    return False
            elif isinstance(op, ast.GtE):
                if not (left >= right):
                    return False
            else:
                raise ValueError(f"Unsupported comparison operator: {op}")
            left = right
        return True
    elif isinstance(node, ast.Name):
        if node.id in context:
            return context[node.id]
        raise ValueError(f"Unknown variable: {node.id}")
    elif isinstance(node, ast.Constant):
        return node.value
