        for series in series_list:
            for val, count in series:
                merged[val] = merged.get(val, 0) + count
        return merged

    def format_series(merged):
        """Format a merged dictionary back into a series string."""
        if not merged:
            return ""
        sorted_items = sorted(merged.items())
        parts = []
        for val, count in sorted_items:
            if count == 1:
                parts.append(str(val))
            else:
