def solve(series_list: list[str], threshold: float) -> list[int]:
    # Parse each series and merge them all
    all_points = []
    for series in series_list:
        if not series.strip():
            continue
        pairs = series.strip().split()
        for pair in pairs:
            if not pair:
                continue
            parts = pair.split(',')
            if len(parts) == 2:
                timestamp = int(parts[0])
                value = float(parts[1])
                all_points.append((timestamp, value))

    # Sort by timestamp
    all_points.sort(key=lambda x: x[0])

    # Compute moving average with window 2
    result = []
    for i in range(len(all_points) - 1):
        avg = (all_points[i][1] + all_points[i + 1][1]) / 2.0
        if avg > threshold:
            result.append(all_points[i][0])

    return result
