def solve(series: str, start: int, end: int) -> list[float]:
    import json
    data = json.loads(series)
    values = [entry["value"] for entry in data if start <= entry["timestamp"] <= end]
    if not values:
        return []
    min_v = min(values)
    max_v = max(values)
    if max_v == min_v:
        return [0.0] * len(values)
    return [(v - min_v) / (max_v - min_v) for v in values]
